_MEMBER_COUNTERPARTY_ID_Deri = -2, NULL, 'NO_ERROR' ) AS IAV_MEMBER_COUNTERPARTY_ID, 'MEM_CPARTY_ID : ' || v_MEMBER_COUNTERPARTY_ID_Deri AS IAOV_MEMBER_COUNTERPARTY_ID FROM EXP_TRIM_TRAILING_SPACES_variableOut AS EXP_TRIM_TRAILING_SPACES_variableOut LEFT JOIN ( SELECT ID, CURRENCY_MNEMONIC FROM ( SELECT ID, CURRENCY_MNEMONIC, ROW_NUMBER() OVER (PARTITION BY CURRENCY_MNEMONIC ORDER BY rnk_fst DESC NULLS LAST) AS rnk_lst FROM ( SELECT ID, CURRENCY_MNEMONIC, ROW_NUMBER() OVER (PARTITION BY CURRENCY_MNEMONIC ORDER BY CURRENCY_MNEMONIC NULLS LAST) AS rnk_fst FROM ( SELECT * FROM CURRENCY_DIM ) lkp_inner ) lkp_outer WHERE rnk_lst = 1 ) dsf_1 ON dsf_1.CURRENCY_MNEMONIC = CURRENCYCODE ),

